dslRule:
/*!id: logical.simplification.double-negation.equality-both-negated*/
/*!description: Simplify !!A == !!B to A == B.*/
/*!severity: info*/
org.eclipse.jdt.core.dom.PrefixExpression.Operator.NOT $x == org.eclipse.jdt.core.dom.PrefixExpression.Operator.NOT $y
=> $x == $y
;;

/*!id: logical.simplification.double-negation.inequality-both-negated*/
/*!description: Simplify !!A != !!B to A ^ B (logical XOR).*/
/*!severity: info*/
org.eclipse.jdt.core.dom.PrefixExpression.Operator.NOT $x != org.eclipse.jdt.core.dom.PrefixExpression.Operator.NOT $y
=> $x ^ $y
;;

/*!id: logical.simplification.double-negation.xor-left-negated*/
/*!description: Simplify !A ^ B to A == B.*/
/*!severity: info*/
org.eclipse.jdt.core.dom.PrefixExpression.Operator.NOT $x ^ $y
=> $x == $y
;;

/*!id: logical.simplification.double-negation.xor-right-negated*/
/*!description: Simplify A ^ !B to A == B.*/
/*!severity: info*/
$x ^ org.eclipse.jdt.core.dom.PrefixExpression.Operator.NOT $y
=> $x == $y
;;

/*!id: null.safety.remove-redundant-null-check.instanceof*/
/*!description: Remove redundant null check before an instanceof expression when the expression has no side effects.*/
/*!severity: info*/
($x != null) && ($x instanceof $Type) :: hasNoSideEffect($x)
=> $x instanceof $Type
;;

/*!id: null.safety.remove-redundant-null-check.instanceof.reversed*/
/*!description: Remove redundant null check before an instanceof expression (reversed operands) when the expression has no side effects.*/
/*!severity: info*/
(null != $x) && ($x instanceof $Type) :: hasNoSideEffect($x)
=> $x instanceof $Type
;;

/*!id: null.safety.remove-redundant-null-check.string-equals*/
