dslRuleAfterChange:
/*!id: numeric.precision.float-to-double*/
/*!description: Convert float literals to double literals to improve numeric precision, as identified by FindBugs FL_MATH_USING_FLOAT_PRECISION.*/
/*!severity: warning*/
/*!minJavaVersion: 8*/
/*!tags: correctness, numeric, precision*/

// Rule for method call argument (requires literal matching and conversion)
org.eclipse.jdt.ui.text.java.hover.SourceViewerInformationControl.blend($bg, $fg, $float_literal_val)
:: $float_literal_val isFloatLiteral() && inMethod("blend")
=> org.eclipse.jdt.ui.text.java.hover.SourceViewerInformationControl.blend($bg, $fg, $float_literal_val.toDouble())
;;

// Rule for variable declaration (requires primitive type change)
float $var = $init;
:: inMethod("blend")
=> double $var = $init;
;;

// Rule for inline float literals within expressions (requires literal matching and conversion)
$expr_part_float
:: $expr_part_float isFloatLiteral() && inMethod("blend")
=> $expr_part_float.toDouble()
;;

// Note: Changing method signature (parameter type) and splitting statements (one assert into two) are complex structural changes not covered by these proposed DSL extensions for expressions/declarations.
